+/*!
+ * @brief Invokes the given functor with the given message casted to the actual type of the given message and the
+ *   optionally passed additional arguments.
+ * For array messages the method is invoked with the given message casted to ArrayMessageBase.
+ * This can be used with invoke_for_array_message to call for the concrete array message type.
+ * @return The return value of the invoked method.
+ */
+template<typename Callable, typename... Args>
+auto invoke_for_message( Message &msg, Callable &&f, Args &&...args );
+
+//! @copydoc invoke_for_message
+template<typename Callable, typename... Args>
+auto invoke_for_message( const Message &msg, Callable &&f, Args &&...args );
+
+/*!
+ * @brief Invokes the given functor with the given value message casted to the actual type of the given message and the
+ *   optionally passed additional arguments.
+ *
+ * @return The return value of the invoked method.
+ * @throws BabelFishException If the message is not a ValueMessage.
+ */
+template<typename Callable, typename... Args>
+auto invoke_for_value_message( Message &msg, Callable &&f, Args &&...args );
+
+//! @copydoc invoke_for_value_message
+template<typename Callable, typename... Args>
+auto invoke_for_value_message( const Message &msg, Callable &&f, Args &&...args );
+
+/*!
+ * @brief Invokes the given functor with the given message casted to the actual type of the given array message and the
+ *   optionally passed additional arguments.
+ *
+ * @return The return value of the invoked method.
+ */
+template<typename Callable, typename... Args>
+auto invoke_for_array_message( ArrayMessageBase &msg, Callable &&f, Args &&...args );
+
