+      return RBF2_INVOKE_FN( f,
+                             msg.as<ArrayMessage_<value_type<MessageTypes::WString>::value, BOUNDED, FIXED_LENGTH>>(),
+                             std::forward<Args>( args )... );
+    case MessageTypes::Compound:
+      return RBF2_INVOKE_FN( f, msg.as<CompoundArrayMessage_<BOUNDED, FIXED_LENGTH>>(),
+                             std::forward<Args>( args )... );
+    case MessageTypes::Array:
+      throw BabelFishException( "Arrays of arrays are not supported in ROS2!" );
+    case MessageTypes::None:
+    default:
+      throw BabelFishException( "invoke_for_array_message called with invalid message!" );
+  }
+}
+}
+
+template<typename Callable, typename... Args>
+auto invoke_for_array_message( ArrayMessageBase &msg, Callable &&f, Args &&...args )
+{
+  if ( msg.isFixedSize())
+    return impl::call_for_array_message<true, true>( msg, std::forward<Callable>( f ), std::forward<Args>( args )... );
+  if ( msg.isBounded())
+    return impl::call_for_array_message<true, false>( msg, std::forward<Callable>( f ), std::forward<Args>( args )... );
+  return impl::call_for_array_message<false, false>( msg, std::forward<Callable>( f ), std::forward<Args>( args )... );
+}
+
+template<typename Callable, typename... Args>
+auto invoke_for_array_message( const ArrayMessageBase &msg, Callable &&f, Args &&...args )
+{
+  if ( msg.isFixedSize())
+    return impl::call_for_array_message<true, true>( msg, std::forward<Callable>( f ), std::forward<Args>( args )... );
+  if ( msg.isBounded())
+    return impl::call_for_array_message<true, false>( msg, std::forward<Callable>( f ), std::forward<Args>( args )... );
+  return impl::call_for_array_message<false, false>( msg, std::forward<Callable>( f ), std::forward<Args>( args )... );
+}
+}
+
+#undef RBF2_INVOKE_FN
+
+#endif //ROS2_BABEL_FISH_METHOD_INVOKE_HELPERS_HPP

