+
+MessageTypeSupport::ConstSharedPtr LocalTypeSupportProvider::getMessageTypeSupportImpl( const std::string &type ) const
+{
+  auto type_support_library = get_typesupport_library(
+    type, rosidl_typesupport_cpp::typesupport_identifier );
+  auto type_support_handle = get_typesupport_handle(
+    type, rosidl_typesupport_cpp::typesupport_identifier, type_support_library );
+  auto introspection_type_support_library = get_typesupport_library(
+    type, rosidl_typesupport_introspection_cpp::typesupport_identifier );
+  auto introspection_type_support_handle = get_typesupport_handle(
+    type, rosidl_typesupport_introspection_cpp::typesupport_identifier, introspection_type_support_library );
+  return registerMessage( type, type_support_library, *type_support_handle,
+                          introspection_type_support_library, *introspection_type_support_handle );
+}
+
+ServiceTypeSupport::ConstSharedPtr LocalTypeSupportProvider::getServiceTypeSupportImpl( const std::string &type ) const
+{
+  auto type_support_library = get_typesupport_library( type, rosidl_typesupport_cpp::typesupport_identifier );
+  auto type_support_handle = get_service_typesupport_handle(
+    type, rosidl_typesupport_cpp::typesupport_identifier, type_support_library );
+  // For introspection the cpp version is available
+  auto introspection_type_support_library = get_typesupport_library(
+    type, rosidl_typesupport_introspection_cpp::typesupport_identifier );
+  auto introspection_type_support_handle = get_service_typesupport_handle(
+    type, rosidl_typesupport_introspection_cpp::typesupport_identifier, introspection_type_support_library );
+  return registerService( type, type_support_library, *type_support_handle,
+                          introspection_type_support_library, *introspection_type_support_handle );
+}
+
+ActionTypeSupport::ConstSharedPtr LocalTypeSupportProvider::getActionTypeSupportImpl( const std::string &type ) const
+{
+  auto type_support_library = get_typesupport_library( type, rosidl_typesupport_cpp::typesupport_identifier );
+  auto type_support_handle = get_action_typesupport_handle(
+    type, rosidl_typesupport_cpp::typesupport_identifier, type_support_library );
+  auto introspection_type_support_library = get_typesupport_library(
+    type, rosidl_typesupport_introspection_cpp::typesupport_identifier );
+
+  // There is no method to get the whole action introspection type support, hence, we need to get each separately
+  rosidl_action_type_support_t introspection;
+  introspection.goal_service_type_support = get_service_typesupport_handle( type + "_SendGoal",
+                                                                            rosidl_typesupport_introspection_cpp::typesupport_identifier,
+                                                                            introspection_type_support_library );
+  introspection.result_service_type_support = get_service_typesupport_handle( type + "_GetResult",
+                                                                              rosidl_typesupport_introspection_cpp::typesupport_identifier,
+                                                                              introspection_type_support_library );
+  introspection.feedback_message_type_support = get_typesupport_handle( type + "_FeedbackMessage",
+                                                                        rosidl_typesupport_introspection_cpp::typesupport_identifier,
+                                                                        introspection_type_support_library );
+  auto result = std::make_shared<ActionTypeSupport>();
+  result->name = type;
+  result->type_support_library = type_support_library;
+  result->type_support_handle = *type_support_handle;
+  result->introspection_type_support_library = introspection_type_support_library;
+
+  result->goal_service_type_support = registerService( type + "_SendGoal",
+                                                       type_support_library,
+                                                       *type_support_handle->goal_service_type_support,
+                                                       introspection_type_support_library,
+                                                       *introspection.goal_service_type_support );
+  result->result_service_type_support = registerService( type + "_GetResult",
+                                                         type_support_library,
+                                                         *type_support_handle->result_service_type_support,
+                                                         introspection_type_support_library,
+                                                         *introspection.result_service_type_support );
+  result->feedback_message_type_support = registerMessage( type + "_FeedbackMessage",
+                                                           type_support_library,
+                                                           *type_support_handle->feedback_message_type_support,
+                                                           introspection_type_support_library,
+                                                           *introspection.feedback_message_type_support );
+
+  // The other type supports are from a different package and we have to look them up
+  result->cancel_service_type_support = getServiceTypeSupport( "action_msgs/srv/CancelGoal" );
+  result->status_message_type_support = getMessageTypeSupport( "action_msgs/msg/GoalStatusArray" );
+  introspection.cancel_service_type_support = &result->cancel_service_type_support->introspection_type_support_handle;
+  introspection.status_message_type_support = &result->status_message_type_support->introspection_type_support_handle;
+  result->introspection_type_support_handle = introspection;
+
+  return registerAction( type, result );
+}
