+  pose_reference.header.stamp = rclcpp::Time( 13.37 );
+  pose_reference.header.frame_id = "babel_fish_frame";
+  pose_reference.pose.position.x = 1.23;
+  pose_reference.pose.position.y = 1.23;
+  pose_reference.pose.position.z = 1.23;
