+  testing::InitGoogleTest( &argc, argv );
+  rclcpp::init( argc, argv );
+  node = std::make_shared<rclcpp::Node>( "test_message_decoding" );
+  int result = RUN_ALL_TESTS();
+  node.reset();
+  return result;
+}

